class Solution:
    def smallestNumber(self, pattern: str) -> str:
        n = len(pattern)
        digits = [str(i) for i in range(9, 0, -1)]
        res = ['0'] * (n + 1)
        increasing = True
        for i in range(n):
            if pattern[i] == 'I':
                increasing = True
            else:
                increasing = False
            if increasing:
                res[i + 1] = min(res[i + 1], digits.pop())
            else:
                res[i] = max(res[i], digits.pop())
        return ''.join(res)
